            new Employee { FirstName = "Jane", LastName = "Doe", EmployeeId = 102, Salary = 75000.0M } 
        };

        bool areEqual = list1.SequenceEqual(list2.OfType<Person>(), 
                        new PersonComparer());

        Console.WriteLine($"Lists are equal: {areEqual}");
